import React from 'react';
import "react-step-progress-bar/styles.css";
import { ProgressBar, Step } from "react-step-progress-bar";
import Flag1 from '../images/flag1.png'
import Flag2 from '../images/flag2.png'
import Flag3 from '../images/flag3.png'
import Car from '../images/car.png'
import Grad from '../images/grad.png'
import ReactTooltip from "react-tooltip";

const MyProgressBar = () => {


    return(
        <div className="progress">
            <ReactTooltip />
            <ProgressBar percent={90} filledBackground="rgb(66,194,255)">
                
                <Step transition="scale">
                {({ accomplished }) => (
                    <img
                    style={{ filter: `grayscale(${accomplished ? 0 : 80}%)` }}
                    width="45"
                    src={Car}
                    alt="Początek studiów"
                    data-tip="Początek studiów"
                    />
                )}
                
                </Step>

                <Step transition="scale">
                {({ accomplished }) => (
                    <img
                    style={{ filter: `grayscale(${accomplished ? 0 : 80}%)` }}
                    width="30"
                    src={Flag1}
                    alt="Pierwszy rok"
                    data-tip="Pierwszy rok"
                    />
                )}
                </Step>

                <Step transition="scale">
                {({ accomplished }) => (
                    <img
                    style={{ filter: `grayscale(${accomplished ? 0 : 80}%)` }}
                    width="30"
                    src={Flag2}
                    alt="Drugi rok"
                    data-tip="Drugi rok"
                    />
                )}
                </Step>

                <Step transition="scale">
                {({ accomplished }) => (
                    <img
                    style={{ filter: `grayscale(${accomplished ? 0 : 80}%)` }}
                    width="30"
                    src={Flag3}
                    alt="Trzeci rok"
                    data-tip="Trzeci rok"
                    />
                )}
                </Step>

                <Step transition="scale">
                {({ accomplished }) => (
                    <img
                    style={{ filter: `grayscale(${accomplished ? 0 : 80}%)` }}
                    width="30"
                    src={Grad}
                    alt="Obrona"
                    data-tip="Obrona"
                    />
                )}
                </Step>

            </ProgressBar>
        </div>
    );

}

export default MyProgressBar;