import React from 'react';
import Mask from '../images/mask.png'
import Menu from '../images/menu.png'

const NavBar = (props) => {



    return(
        <div className="nav">
            <img src={Mask} alt="Grafika maski Guya Fawkesa" height="40"></img>
            <img src={Menu} onClick={() => props.change(!props.active)} alt="Grafika maski Guya Fawkesa" height="40" style={{float: 'right', zIndex: '10'}}></img>
            
        </div>
    );

}

export default NavBar;